import { create } from "zustand";
import { regions, type Region, defaultUnlockedRegions } from "@/data/regions";

export interface RegionAnswer {
  questionId: number;
  correct: boolean;
}

export interface PlayerProgress {
  unlockedRegions: number[];
  regionStars: Record<number, number>;
  regionAnswers: Record<number, RegionAnswer[]>;
  completedRegions: number[];
}

export type QuizStatus = "idle" | "taking" | "answered" | "finished";

interface GameState {
  playerProgress: PlayerProgress;
  currentRegion: Region | null;
  currentQuestionIndex: number;
  quizStatus: QuizStatus;
  selectedAnswer: number | null;
  isCorrect: boolean | null;

  // Actions
  setCurrentRegion: (region: Region | null) => void;
  startQuiz: (regionId: number) => void;
  submitAnswer: (optionIndex: number) => void;
  nextQuestion: () => void;
  finishQuiz: () => void;
  resetQuiz: () => void;
  resetAllProgress: () => void;
}

const STORAGE_KEY = "logistics_knowledge_progress";

function loadProgress(): PlayerProgress {
  try {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      return JSON.parse(saved);
    }
  } catch {
    // ignore
  }
  return {
    unlockedRegions: [...defaultUnlockedRegions],
    regionStars: {},
    regionAnswers: {},
    completedRegions: [],
  };
}

function saveProgress(progress: PlayerProgress) {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(progress));
  } catch {
    // ignore
  }
}

export const useGameStore = create<GameState>((set, get) => ({
  playerProgress: loadProgress(),
  currentRegion: null,
  currentQuestionIndex: 0,
  quizStatus: "idle",
  selectedAnswer: null,
  isCorrect: null,

  setCurrentRegion: (region) => {
    set({ currentRegion: region });
  },

  startQuiz: (regionId) => {
    const region = regions.find((r) => r.id === regionId);
    if (!region) return;
    set({
      currentRegion: region,
      currentQuestionIndex: 0,
      quizStatus: "taking",
      selectedAnswer: null,
      isCorrect: null,
    });
  },

  submitAnswer: (optionIndex) => {
    const state = get();
    const region = state.currentRegion;
    if (!region || state.quizStatus !== "taking") return;

    const question = region.questions[state.currentQuestionIndex];
    const correct = optionIndex === question.correctIndex;

    set({
      selectedAnswer: optionIndex,
      isCorrect: correct,
      quizStatus: "answered",
    });
  },

  nextQuestion: () => {
    const state = get();
    const region = state.currentRegion;
    if (!region) return;

    const question = region.questions[state.currentQuestionIndex];
    const isCorrect = state.isCorrect ?? false;

    // Record answer
    const progress = { ...state.playerProgress };
    const regionId = region.id;
    const answers = [...(progress.regionAnswers[regionId] || [])];
    answers.push({ questionId: question.id, correct: isCorrect });
    progress.regionAnswers = { ...progress.regionAnswers, [regionId]: answers };

    // If it's the last question
    if (state.currentQuestionIndex >= region.questions.length - 1) {
      // Calculate stars
      const correctCount = answers.filter((a) => a.correct).length;
      progress.regionStars = { ...progress.regionStars, [regionId]: correctCount };
      if (!progress.completedRegions.includes(regionId)) {
        progress.completedRegions = [...progress.completedRegions, regionId];
      }
      // Unlock next region
      const nextRegionId = regionId + 1;
      if (nextRegionId <= regions.length && !progress.unlockedRegions.includes(nextRegionId)) {
        progress.unlockedRegions = [...progress.unlockedRegions, nextRegionId];
      }

      saveProgress(progress);
      set({
        playerProgress: progress,
        quizStatus: "finished",
      });
    } else {
      saveProgress(progress);
      set({
        playerProgress: progress,
        currentQuestionIndex: state.currentQuestionIndex + 1,
        quizStatus: "taking",
        selectedAnswer: null,
        isCorrect: null,
      });
    }
  },

  finishQuiz: () => {
    // Already handled in nextQuestion
  },

  resetQuiz: () => {
    set({
      currentRegion: null,
      currentQuestionIndex: 0,
      quizStatus: "idle",
      selectedAnswer: null,
      isCorrect: null,
    });
  },

  resetAllProgress: () => {
    const freshProgress: PlayerProgress = {
      unlockedRegions: [...defaultUnlockedRegions],
      regionStars: {},
      regionAnswers: {},
      completedRegions: [],
    };
    saveProgress(freshProgress);
    set({ playerProgress: freshProgress });
  },
}));