import { useNavigate } from "react-router-dom";
import { motion } from "framer-motion";
import { regions } from "@/data/regions";
import { useGameStore } from "@/store/gameStore";
import { Star, Lock, Compass } from "lucide-react";

const regionPositions = [
  { x: 14, y: 16 },
  { x: 72, y: 10 },
  { x: 16, y: 68 },
  { x: 68, y: 64 },
];

const roadPaths = [
  "M 190 120 Q 350 80 530 90",
  "M 530 90 Q 600 250 540 380",
  "M 540 380 Q 350 450 200 380",
  "M 200 380 Q 80 250 190 120",
  "M 190 120 Q 350 250 540 380",
];

const particles = [
  { x: 25, y: 30, delay: 0, color: "#C9A84C" },
  { x: 55, y: 20, delay: 1, color: "#D4A574" },
  { x: 40, y: 50, delay: 2, color: "#A8C4D8" },
  { x: 75, y: 40, delay: 0.5, color: "#C9A84C" },
  { x: 30, y: 55, delay: 1.5, color: "#D4A574" },
  { x: 60, y: 60, delay: 2.5, color: "#E8D5A3" },
  { x: 45, y: 75, delay: 0.8, color: "#C9A84C" },
  { x: 80, y: 80, delay: 1.8, color: "#A8C4D8" },
];

export default function MapPage() {
  const navigate = useNavigate();
  const { playerProgress } = useGameStore();

  const totalStars = Object.values(playerProgress.regionStars).reduce(
    (sum, s) => sum + s,
    0
  );

  const rankTitle = (() => {
    if (totalStars >= 18) return "S级 · 综合掌握";
    if (totalStars >= 14) return "A级 · 良好掌握";
    if (totalStars >= 10) return "B级 · 基础掌握";
    if (totalStars >= 6) return "C级 · 初步了解";
    return "D级 · 入门阶段";
  })();

  return (
    <div className="relative w-full h-full min-h-screen overflow-hidden parchment-bg">
      <div className="map-border map-border-top" />
      <div className="map-border map-border-bottom" />
      <div className="map-border map-border-left" />
      <div className="map-border map-border-right" />
      <div className="map-corner map-corner-tl" />
      <div className="map-corner map-corner-tr" />
      <div className="map-corner map-corner-bl" />
      <div className="map-corner map-corner-br" />

      {particles.map((p, i) => (
        <div
          key={i}
          className="map-particle"
          style={{
            left: `${p.x}%`,
            top: `${p.y}%`,
            backgroundColor: p.color,
            animationDelay: `${p.delay}s`,
            width: "3px",
            height: "3px",
          }}
        />
      ))}

      <motion.div
        className="relative z-10 pt-4 pb-1 text-center"
        initial={{ opacity: 0, y: -10 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.5 }}
      >
        <h1
          className="font-medieval text-3xl md:text-4xl tracking-wider"
          style={{ color: "#5C3D2E" }}
        >
          物流运筹学知识体系
        </h1>
        <p className="font-cn text-sm mt-0.5" style={{ color: "#8B7355" }}>
          学习地图
        </p>

        <div className="flex items-center justify-center gap-3 mt-2">
          <span
            className="font-cn text-xs font-bold px-3 py-1 rounded-full"
            style={{
              background: "rgba(201, 168, 76, 0.2)",
              color: "#8B6914",
              border: "1px solid rgba(201, 168, 76, 0.3)",
            }}
          >
            {rankTitle}
          </span>
          <span className="flex items-center gap-1 text-sm" style={{ color: "#C9A84C" }}>
            <Star size={14} className="fill-[#C9A84C]" />
            {totalStars}/20
          </span>
        </div>
      </motion.div>

      <div className="relative z-10 mx-auto" style={{ maxWidth: "900px", height: "calc(100vh - 130px)" }}>
        <svg
          className="absolute inset-0 w-full h-full pointer-events-none"
          viewBox="0 0 100 100"
          preserveAspectRatio="xMidYMid meet"
        >
          <ellipse cx="30" cy="30" rx="22" ry="18" fill="#C4A97D" opacity="0.08" />
          <ellipse cx="70" cy="25" rx="20" ry="16" fill="#C4A97D" opacity="0.08" />
          <ellipse cx="25" cy="70" rx="18" ry="22" fill="#C4A97D" opacity="0.08" />
          <ellipse cx="70" cy="68" rx="20" ry="18" fill="#C4A97D" opacity="0.08" />
          <ellipse cx="50" cy="50" rx="25" ry="20" fill="#C4A97D" opacity="0.06" />
          <ellipse cx="50" cy="50" rx="8" ry="6" fill="#A8C4D8" opacity="0.15" />
          <ellipse cx="85" cy="50" rx="5" ry="8" fill="#A8C4D8" opacity="0.1" />
          <ellipse cx="15" cy="50" rx="4" ry="7" fill="#A8C4D8" opacity="0.1" />

          {roadPaths.map((path, i) => {
            const pairs = [[0,1],[1,3],[3,2],[2,0],[0,3]];
            const [from, to] = pairs[i];
            const r1Unlocked = playerProgress.unlockedRegions.includes(from + 1);
            const r2Unlocked = playerProgress.unlockedRegions.includes(to + 1);
            const isActive = r1Unlocked || r2Unlocked;

            return (
              <path
                key={i}
                d={path}
                fill="none"
                stroke={isActive ? "#8B7355" : "#C4A97D"}
                strokeWidth={isActive ? 0.6 : 0.3}
                strokeDasharray={isActive ? "1.5,2" : "1,3"}
                opacity={isActive ? 0.5 : 0.2}
                className={isActive ? "animate-road-pulse" : ""}
                style={isActive ? { animation: "road-pulse 3s ease-in-out infinite" } : {}}
                transform="scale(0.9) translate(5.5, 5.5)"
              />
            );
          })}

          <circle cx="35" cy="22" r="0.3" fill="#8B7355" opacity="0.3" />
          <circle cx="45" cy="18" r="0.3" fill="#8B7355" opacity="0.3" />
          <circle cx="55" cy="28" r="0.3" fill="#8B7355" opacity="0.3" />
          <circle cx="65" cy="45" r="0.3" fill="#8B7355" opacity="0.3" />
          <circle cx="55" cy="55" r="0.3" fill="#8B7355" opacity="0.3" />
          <circle cx="40" cy="50" r="0.3" fill="#8B7355" opacity="0.3" />
        </svg>

        {regions.map((region, index) => {
          const isUnlocked = playerProgress.unlockedRegions.includes(region.id);
          const stars = playerProgress.regionStars[region.id] ?? 0;
          const isCompleted = playerProgress.completedRegions.includes(region.id);
          const pos = regionPositions[index];

          return (
            <div
              key={region.id}
              className="absolute"
              style={{
                left: `${pos.x}%`,
                top: `${pos.y}%`,
                transform: "translate(-50%, -50%)",
                zIndex: isUnlocked ? 5 : 3,
              }}
            >
              <motion.button
                className="relative flex flex-col items-center"
                onClick={() => isUnlocked && navigate(`/region/${region.id}`)}
                initial={{ opacity: 0, scale: 0.5 }}
                animate={{ opacity: 1, scale: 1 }}
                transition={{ delay: index * 0.15, duration: 0.4, ease: "easeOut" as const }}
                whileHover={isUnlocked ? { scale: 1.1 } : {}}
                whileTap={isUnlocked ? { scale: 0.95 } : {}}
                disabled={!isUnlocked}
              >
                <div
                  className="relative flex items-center justify-center rounded-full"
                  style={{
                    width: 80,
                    height: 80,
                    background: isUnlocked
                      ? `radial-gradient(circle at 35% 35%, ${region.secondaryColor}44, ${region.color}88)`
                      : "rgba(180, 160, 130, 0.3)",
                    border: `3px solid ${
                      isUnlocked ? region.color : "rgba(180, 160, 130, 0.3)"
                    }`,
                    boxShadow: isUnlocked
                      ? `0 0 20px ${region.color}33, 0 4px 12px rgba(0,0,0,0.1)`
                      : "none",
                  }}
                >
                  <span
                    className="text-3xl select-none"
                    style={{
                      filter: isUnlocked ? "none" : "grayscale(1)",
                      opacity: isUnlocked ? 1 : 0.4,
                    }}
                  >
                    {region.icon}
                  </span>

                  {isCompleted && (
                    <div
                      className="absolute -top-1 -right-1 w-6 h-6 rounded-full flex items-center justify-center text-xs font-bold text-white"
                      style={{ background: "#C9A84C" }}
                    >
                      ✓
                    </div>
                  )}
                </div>

                <div
                  className="mt-1.5 px-2.5 py-0.5 rounded"
                  style={{
                    background: isUnlocked
                      ? "rgba(242, 232, 207, 0.9)"
                      : "rgba(242, 232, 207, 0.5)",
                    border: `1px solid ${
                      isUnlocked ? region.color + "55" : "transparent"
                    }`,
                  }}
                >
                  <p
                    className="font-cn text-xs font-bold whitespace-nowrap"
                    style={{ color: isUnlocked ? "#3d2b1f" : "#aaa" }}
                  >
                    {region.name}
                  </p>
                  <p
                    className="font-cn text-[10px] whitespace-nowrap"
                    style={{ color: isUnlocked ? "#8B7355" : "#bbb" }}
                  >
                    {region.shortDesc}
                  </p>
                </div>

                <div className="flex items-center gap-0.5 mt-1">
                  {Array.from({ length: 5 }, (_, i) => (
                    <Star
                      key={i}
                      size={10}
                      className={
                        i < stars
                          ? "fill-[#C9A84C] text-[#C9A84C]"
                          : "text-[#D4C5A0]"
                      }
                    />
                  ))}
                </div>

                {!isUnlocked && (
                  <div className="absolute inset-0 flex items-center justify-center">
                    <div className="flex flex-col items-center gap-1">
                      <Lock size={20} className="text-[#C4A97D]" style={{ opacity: 0.6 }} />
                      <div
                        className="text-[10px] font-cn font-bold px-2 py-0.5 rounded"
                        style={{
                          background: "rgba(180, 160, 130, 0.3)",
                          color: "#C4A97D",
                        }}
                      >
                        未解锁
                      </div>
                    </div>
                  </div>
                )}
              </motion.button>
            </div>
          );
        })}

        <motion.div
          className="absolute"
          style={{ bottom: "10%", right: "5%" }}
          initial={{ opacity: 0, rotate: -30 }}
          animate={{ opacity: 1, rotate: 0 }}
          transition={{ delay: 1, duration: 0.6 }}
        >
          <div className="flex flex-col items-center gap-1">
            <Compass size={28} style={{ color: "#8B7355" }} />
            <span className="font-cn text-[10px]" style={{ color: "#8B7355" }}>N</span>
          </div>
        </motion.div>

        <motion.div
          className="absolute"
          style={{ bottom: "10%", left: "5%" }}
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ delay: 1.2, duration: 0.5 }}
        >
          <div
            className="rounded-lg p-2"
            style={{
              background: "rgba(242, 232, 207, 0.8)",
              border: "1px solid rgba(139, 115, 85, 0.2)",
            }}
          >
            <p className="font-cn text-[10px]" style={{ color: "#8B7355" }}>
              点击已解锁章节开始答题
            </p>
          </div>
        </motion.div>
      </div>
    </div>
  );
}