import { useParams, useNavigate } from "react-router-dom";
import { motion, AnimatePresence } from "framer-motion";
import { regions } from "@/data/regions";
import { useGameStore } from "@/store/gameStore";
import { useEffect, useState } from "react";
import { ChevronRight, Swords, Skull, ArrowLeft } from "lucide-react";

export default function QuizPage() {
  const { id } = useParams();
  const navigate = useNavigate();
  const {
    currentRegion,
    currentQuestionIndex,
    quizStatus,
    selectedAnswer,
    isCorrect,
    startQuiz,
    submitAnswer,
    nextQuestion,
  } = useGameStore();

  const [showFeedback, setShowFeedback] = useState(false);
  const [showNext, setShowNext] = useState(false);

  const regionId = Number(id);
  const region = regions.find((r) => r.id === regionId);

  useEffect(() => {
    if (!currentRegion || currentRegion.id !== regionId) {
      startQuiz(regionId);
    }
  }, [regionId, currentRegion, startQuiz]);

  useEffect(() => {
    setShowFeedback(false);
    setShowNext(false);
  }, [currentQuestionIndex]);

  if (!region) {
    return (
      <div className="w-full h-full flex items-center justify-center parchment-bg">
        <p className="font-cn" style={{ color: "#8B7355" }}>章节不存在</p>
      </div>
    );
  }

  const question = region.questions[currentQuestionIndex];
  const totalQuestions = region.questions.length;
  const progressPercent = (currentQuestionIndex / totalQuestions) * 100;
  const displayQuestionNum = Math.min(currentQuestionIndex + 1, totalQuestions);

  if (!question) {
    return (
      <div className="w-full h-full flex items-center justify-center parchment-bg">
        <p className="font-cn" style={{ color: "#8B7355" }}>加载中...</p>
      </div>
    );
  }

  const handleOptionClick = (index: number) => {
    if (quizStatus !== "taking") return;
    submitAnswer(index);
    setShowFeedback(true);
    setTimeout(() => setShowNext(true), 800);
  };

  const handleNext = () => {
    if (currentQuestionIndex >= totalQuestions - 1) {
      nextQuestion();
      navigate("/result");
    } else {
      nextQuestion();
    }
  };

  const handleSkipToResult = () => {
    const store = useGameStore.getState();
    store.nextQuestion();
    navigate("/result");
  };

  return (
    <div className="relative w-full h-full min-h-screen overflow-hidden parchment-bg">
      <div className="map-corner map-corner-tl" />
      <div className="map-corner map-corner-tr" />
      <div className="map-corner map-corner-bl" />
      <div className="map-corner map-corner-br" />

      <div className="relative z-10 flex flex-col h-full min-h-screen">
        {/* Header */}
        <div className="px-4 md:px-8 pt-6 pb-4">
          <div className="flex items-center justify-between mb-4">
            <div className="flex items-center gap-2">
              <button
                onClick={() => navigate("/")}
                style={{ color: "#8B7355" }}
                className="hover:opacity-70 transition-opacity"
              >
                <ArrowLeft size={18} />
              </button>
              <span className="text-2xl">{region.icon}</span>
              <span className="font-cn font-bold text-sm" style={{ color: region.color }}>
                {region.name}
              </span>
              <span className="font-cn text-xs" style={{ color: "#8B7355" }}>
                · 章节测验
              </span>
            </div>

            <button
              onClick={handleSkipToResult}
              className="font-cn text-xs"
              style={{ color: "#8B7355" }}
            >
              跳过
            </button>
          </div>

          {/* Progress bar */}
          <div className="flex items-center gap-3 mb-3">
            <div className="flex items-center gap-1.5">
              <Swords size={14} style={{ color: region.color }} />
              <span className="font-cn text-xs" style={{ color: "#8B7355" }}>进度</span>
            </div>
            <div className="flex-1 h-3 rounded-full overflow-hidden" style={{ background: "rgba(139, 115, 85, 0.15)" }}>
              <motion.div
                className="h-full rounded-full"
                style={{
                  background: `linear-gradient(90deg, ${region.color}, ${region.secondaryColor})`,
                }}
                initial={{ width: "100%" }}
                animate={{ width: `${100 - progressPercent}%` }}
                transition={{ duration: 0.5 }}
              />
            </div>
          </div>

          {/* Progress dots */}
          <div className="flex items-center gap-2">
            {Array.from({ length: totalQuestions }, (_, i) => (
              <div
                key={i}
                className="h-1.5 rounded-full transition-all duration-300"
                style={{
                  width: i < currentQuestionIndex ? "24px" : i === currentQuestionIndex ? "32px" : "12px",
                  background:
                    i < currentQuestionIndex
                      ? region.color
                      : i === currentQuestionIndex
                      ? `${region.color}80`
                      : "rgba(139, 115, 85, 0.15)",
                }}
              />
            ))}
            <span className="font-cn text-xs ml-2" style={{ color: "#8B7355" }}>
              {displayQuestionNum}/{totalQuestions}
            </span>
          </div>
        </div>

        {/* Question Area */}
        <div className="flex-1 flex flex-col items-center justify-center px-4 md:px-8 pb-4">
          <AnimatePresence mode="wait">
            <motion.div
              key={currentQuestionIndex}
              className="w-full max-w-2xl"
              initial={{ opacity: 0, x: 50 }}
              animate={{ opacity: 1, x: 0 }}
              exit={{ opacity: 0, x: -50 }}
              transition={{ duration: 0.3 }}
            >
              <motion.div
                className="rounded-xl p-5 md:p-6 mb-5"
                style={{
                  background: "rgba(255, 255, 255, 0.5)",
                  border: "1px solid rgba(139, 115, 85, 0.15)",
                  boxShadow: "0 2px 12px rgba(0,0,0,0.04)",
                }}
              >
                <div className="flex items-center gap-2 mb-3">
                  <Skull size={16} style={{ color: region.color }} />
                  <span className="font-cn text-xs font-bold" style={{ color: region.color }}>
                    第 {displayQuestionNum} 题
                  </span>
                </div>
                <p className="font-cn text-base md:text-lg leading-relaxed" style={{ color: "#3d2b1f" }}>
                  {question.text}
                </p>
              </motion.div>

              {/* Options */}
              <div className="space-y-3">
                {question.options.map((option, index) => {
                  let optionStyle: React.CSSProperties = {
                    background: "rgba(255, 255, 255, 0.4)",
                    border: "1px solid rgba(139, 115, 85, 0.15)",
                    color: "#3d2b1f",
                  };

                  const isSelected = selectedAnswer === index;
                  const isCorrectOption = index === question.correctIndex;

                  if (quizStatus === "answered") {
                    if (isCorrectOption) {
                      optionStyle = {
                        background: "rgba(46, 204, 113, 0.1)",
                        border: "1px solid rgba(46, 204, 113, 0.4)",
                        color: "#1a6b3c",
                      };
                    } else if (isSelected) {
                      optionStyle = {
                        background: "rgba(231, 76, 60, 0.08)",
                        border: "1px solid rgba(231, 76, 60, 0.4)",
                        color: "#8b1a1a",
                      };
                    } else {
                      optionStyle = {
                        background: "rgba(255, 255, 255, 0.2)",
                        border: "1px solid rgba(139, 115, 85, 0.08)",
                        color: "#8B7355",
                        opacity: 0.5,
                      };
                    }
                  }

                  const optionLabels = ["A", "B", "C", "D"];

                  return (
                    <motion.button
                      key={index}
                      className="w-full text-left rounded-xl p-4 transition-all duration-200 flex items-center gap-3 font-cn"
                      style={optionStyle}
                      onClick={() => handleOptionClick(index)}
                      disabled={quizStatus !== "taking"}
                      whileHover={quizStatus === "taking" ? { scale: 1.01, borderColor: region.color } : {}}
                      whileTap={quizStatus === "taking" ? { scale: 0.99 } : {}}
                      animate={quizStatus === "answered" && isCorrectOption ? { scale: [1, 1.02, 1] } : {}}
                      transition={{ duration: 0.3 }}
                    >
                      <span
                        className="w-7 h-7 rounded-full flex items-center justify-center text-xs font-bold flex-shrink-0"
                        style={{
                          background:
                            quizStatus === "answered" && isCorrectOption
                              ? "rgba(46, 204, 113, 0.2)"
                              : quizStatus === "answered" && isSelected
                              ? "rgba(231, 76, 60, 0.2)"
                              : "rgba(139, 115, 85, 0.15)",
                          color:
                            quizStatus === "answered" && (isCorrectOption || isSelected)
                              ? "#fff"
                              : "#8B7355",
                        }}
                      >
                        {optionLabels[index]}
                      </span>
                      <span className="text-sm md:text-base">{option}</span>
                      {quizStatus === "answered" && isCorrectOption && (
                        <span className="ml-auto text-green-600 text-lg">✓</span>
                      )}
                      {quizStatus === "answered" && isSelected && !isCorrectOption && (
                        <span className="ml-auto text-red-500 text-lg">✗</span>
                      )}
                    </motion.button>
                  );
                })}
              </div>
            </motion.div>
          </AnimatePresence>
        </div>

        {/* Feedback + Next button */}
        <div className="px-4 md:px-8 pb-6 max-w-2xl mx-auto w-full">
          <AnimatePresence>
            {showFeedback && (
              <motion.div
                className="mb-4"
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0 }}
              >
                <div
                  className="rounded-xl p-4"
                  style={{
                    background: isCorrect
                      ? "rgba(46, 204, 113, 0.06)"
                      : "rgba(231, 76, 60, 0.06)",
                    border: `1px solid ${
                      isCorrect ? "rgba(46, 204, 113, 0.25)" : "rgba(231, 76, 60, 0.25)"
                    }`,
                  }}
                >
                  <div className="flex items-center gap-2 mb-2">
                    {isCorrect ? (
                      <>
                        <span className="text-green-600 text-lg">✓</span>
                        <span className="font-cn text-green-700 font-bold text-sm">正确！</span>
                      </>
                    ) : (
                      <>
                        <span className="text-red-500 text-lg">✗</span>
                        <span className="font-cn text-red-600 font-bold text-sm">错误！</span>
                      </>
                    )}
                  </div>
                  <p className="font-cn text-xs leading-relaxed" style={{ color: "#5C3D2E" }}>
                    {question.explanation}
                  </p>
                </div>
              </motion.div>
            )}
          </AnimatePresence>

          {showNext && (
            <motion.button
              className="w-full py-3.5 rounded-lg font-bold font-cn text-base transition-all duration-300 hover:scale-[1.01] active:scale-99 flex items-center justify-center gap-2 text-white"
              style={{
                background: `linear-gradient(135deg, ${region.color}, ${region.secondaryColor})`,
                boxShadow: `0 4px 16px ${region.color}44`,
              }}
              onClick={handleNext}
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
            >
              {currentQuestionIndex >= totalQuestions - 1 ? (
                <>查看结果 <ChevronRight size={18} /></>
              ) : (
                <>下一题 <ChevronRight size={18} /></>
              )}
            </motion.button>
          )}
        </div>
      </div>
    </div>
  );
}