const masteryLevels = [
  { min: 0, label: "待突破", color: "#8B7355", desc: "基础概念尚未掌握" },
  { min: 20, label: "初窥门径", color: "#5A9E6F", desc: "已了解基本概念" },
  { min: 40, label: "略有小成", color: "#5B8DB8", desc: "掌握部分核心知识" },
  { min: 60, label: "渐入佳境", color: "#D4782A", desc: "较好理解知识体系" },
  { min: 80, label: "融会贯通", color: "#C9A84C", desc: "熟练掌握并能灵活运用" },
];

function getMasteryLevel(percent: number) {
  let level = masteryLevels[0];
  for (const l of masteryLevels) {
    if (percent >= l.min) level = l;
  }
  return level;
}

