export function generateAIEvaluation(progress: PlayerProgress): AIEvaluation {
  const regionEvaluations: RegionEvaluation[] = regions.map((region) => {
    const stars = progress.regionStars[region.id] ?? 0;
    const percent = (stars / 5) * 100;
    const level = getMasteryLevel(percent);
    const templates = regionEvalTemplates[region.id];

    // Get strengths based on star level
    const strengths = templates.strengths[stars] || [];

    // Get weaknesses (inverse: if 5 stars, show weaknesses for things they might still miss)
    const weaknesses = templates.weaknesses[stars] || [];

    // Get suggestion
    const suggestion = templates.suggestions[stars] || "继续保持！";

    return {
      regionId: region.id,
      regionName: region.name,
      icon: region.icon,
      stars,
      masteryLevel: level.label,
      masteryPercent: percent,
      strengths,
      weaknesses,
      suggestion,
    };
  });

  // Sort by mastery (ascending) to find weakest area
  const sorted = [...regionEvaluations].sort((a, b) => a.stars - b.stars);
  const topStrength = sorted[sorted.length - 1];
  const topWeakness = sorted[0];

  // Overall analysis
  const totalStars = Object.values(progress.regionStars).reduce((s, v) => s + v, 0);
  const overallPercent = (totalStars / 20) * 100;
  const overallLevel = getMasteryLevel(overallPercent);

  // Generate summary based on overall performance
  let summary = "";
  if (totalStars >= 18) {
    summary = "恭喜你！你已全面掌握物流运筹学的四大核心知识领域。从仓储选址到作业调度，你展现出了扎实的分析能力和科学决策水平，能够在确定性和不确定性环境下做出合理的运筹优化决策。";
  } else if (totalStars >= 14) {
    summary = `表现优秀！你在物流运筹学的多个领域展现了良好的功底。在「${topStrength.regionName}」方面掌握较为扎实，但在「${topWeakness.regionName}」方面仍有提升空间。建议集中精力巩固薄弱环节，争取全面掌握。`;
  } else if (totalStars >= 10) {
    summary = `学习进展良好！你已初步掌握物流运筹学的基础知识。目前你在「${topStrength.regionName}」方面表现较好，但「${topWeakness.regionName}」是相对薄弱的知识点。建议加强该领域的理论学习，配合练习巩固。`;
  } else if (totalStars >= 6) {
    summary = `学习已起步！你对物流运筹学有了初步了解，但知识掌握尚不够系统。「${topWeakness.regionName}」是你当前最需要加强的领域。建议从基础概念开始，循序渐进地学习各个知识点。`;
  } else {
    summary = "学习刚刚开始。物流运筹学的知识体系较为广阔，目前需要更系统地学习基础知识。建议先从「仓储选址」和「作业调度」的基础概念入手，逐步建立完整的知识框架。";
  }

  // Final advice
  let finalAdvice = "";
  if (totalStars >= 18) {
    finalAdvice = "你已经具备了物流运筹学专家的潜质！建议将所学知识应用到实际案例中，参与企业物流规划项目，或尝试用编程实现运筹学算法，进一步提升实战能力。";
  } else if (totalStars >= 14) {
    finalAdvice = `建议重点攻克「${topWeakness.regionName}」的相关知识点，可以通过针对性练习和案例学习来提升。同时保持对优势领域的持续学习，做到融会贯通。`;
  } else if (totalStars >= 10) {
    finalAdvice = `你的学习重点应放在「${topWeakness.regionName}」上，建议先复习该领域的基础理论，再逐步挑战复杂问题。同时不要忽视其他知识点的巩固。`;
  } else if (totalStars >= 6) {
    finalAdvice = `建议制定系统的学习计划，从最基础的运筹学概念开始，每天学习一个知识点并配合练习。推荐使用教材或在线课程辅助学习。`;
  } else {
    finalAdvice = "建议回归教材，系统学习运筹学基础知识。可以先从线性规划、整数规划等基础内容入手，逐步扩展到更复杂的运筹学模型。";
  }

  return {
    overallScore: totalStars,
    overallLevel: overallLevel.label,
    summary,
    regionEvaluations,
    topStrength: topStrength.regionName,
    topWeakness: topWeakness.regionName,
    finalAdvice,
  };
}