import { useParams, useNavigate } from "react-router-dom";
import { motion } from "framer-motion";
import { regions } from "@/data/regions";
import { useGameStore } from "@/store/gameStore";
import { ArrowLeft, Swords, Shield } from "lucide-react";

export default function RegionPage() {
  const { id } = useParams();
  const navigate = useNavigate();
  const { startQuiz } = useGameStore();

  const regionId = Number(id);
  const region = regions.find((r) => r.id === regionId);

  if (!region) {
    return (
      <div className="w-full h-full flex items-center justify-center parchment-bg">
        <p className="font-cn" style={{ color: "#8B7355" }}>章节不存在</p>
      </div>
    );
  }

  const handleStartQuiz = () => {
    startQuiz(regionId);
    navigate(`/quiz/${regionId}`);
  };

  return (
    <div className="relative w-full h-full min-h-screen overflow-hidden parchment-bg">
      <div className="map-corner map-corner-tl" />
      <div className="map-corner map-corner-tr" />
      <div className="map-corner map-corner-bl" />
      <div className="map-corner map-corner-br" />

      <motion.button
        className="absolute top-6 left-4 md:left-8 flex items-center gap-2 z-10 font-cn"
        style={{ color: "#8B7355" }}
        onClick={() => navigate("/")}
        initial={{ opacity: 0, x: -20 }}
        animate={{ opacity: 1, x: 0 }}
        transition={{ duration: 0.4 }}
        whileHover={{ color: "#5C3D2E" }}
      >
        <ArrowLeft size={20} />
        <span className="text-sm">返回知识体系</span>
      </motion.button>

      <div className="relative z-10 flex flex-col items-center justify-center min-h-screen px-4 md:px-8 pt-16 pb-8">
        <motion.div
          className="max-w-2xl w-full"
          initial={{ opacity: 0, y: 30 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.5, delay: 0.2 }}
        >
          <div className="text-center mb-8">
            <motion.div
              className="text-6xl mb-4"
              initial={{ scale: 0 }}
              animate={{ scale: 1 }}
              transition={{ type: "spring", stiffness: 200, damping: 15 }}
            >
              {region.icon}
            </motion.div>
            <h1
              className="font-cn font-bold text-3xl md:text-4xl mb-2"
              style={{ color: region.color }}
            >
              {region.name}
            </h1>
            <p className="font-cn text-sm" style={{ color: "#8B7355" }}>
              {region.shortDesc}
            </p>
          </div>

          <motion.div
            className="rounded-xl p-5 mb-4"
            style={{
              background: "rgba(255, 255, 255, 0.4)",
              border: `1px solid ${region.color}44`,
              boxShadow: "0 2px 12px rgba(0,0,0,0.04)",
            }}
            initial={{ opacity: 0, x: -20 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ duration: 0.4, delay: 0.3 }}
          >
            <div className="flex items-center gap-2 mb-3">
              <Shield size={16} style={{ color: region.color }} />
              <h3 className="font-cn font-bold text-sm" style={{ color: region.color }}>
                知识背景
              </h3>
            </div>
            <p className="font-cn text-sm leading-relaxed" style={{ color: "#5C3D2E" }}>
              {region.background}
            </p>
          </motion.div>

          <motion.div
            className="rounded-xl p-5 mb-8"
            style={{
              background: "rgba(255, 255, 255, 0.4)",
              border: "1px solid rgba(201, 168, 76, 0.3)",
              boxShadow: "0 2px 12px rgba(0,0,0,0.04)",
            }}
            initial={{ opacity: 0, x: 20 }}
            animate={{ opacity: 1, x: 0 }}
            transition={{ duration: 0.4, delay: 0.4 }}
          >
            <div className="flex items-center gap-2 mb-3">
              <Swords size={16} style={{ color: "#C9A84C" }} />
              <h3 className="font-cn font-bold text-sm" style={{ color: "#C9A84C" }}>
                核心考察点
              </h3>
            </div>
            <p className="font-cn text-sm leading-relaxed" style={{ color: "#5C3D2E" }}>
              {region.coreConcept}
            </p>
          </motion.div>

          <motion.div
            className="text-center"
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.4, delay: 0.6 }}
          >
            <button
              onClick={handleStartQuiz}
              className="font-cn px-10 py-3.5 rounded-lg font-bold text-base transition-all duration-300 hover:scale-105 active:scale-95 text-white"
              style={{
                background: `linear-gradient(135deg, ${region.color}, ${region.secondaryColor})`,
                boxShadow: `0 4px 16px ${region.color}44`,
              }}
            >
              开始答题
            </button>
            <p className="font-cn text-xs mt-3" style={{ color: "#8B7355" }}>
              共 5 道题，答对获得星数
            </p>
          </motion.div>
        </motion.div>
      </div>
    </div>
  );
}